-- Source: 43tables_schema/*.md (MOPH 43-file structure standard v2.4.1)
-- 1 row = 1 field of a file schema; file_name tells which แฟ้ม the row belongs to
SET NAMES utf8mb3;

DROP TABLE IF EXISTS `c_files_schema`;

CREATE TABLE `c_files_schema` (
  `file_name` varchar(50) NOT NULL,
  `table_name` varchar(50) NOT NULL,
  `no` int NOT NULL,
  `caption` varchar(255) DEFAULT NULL,
  `description` text DEFAULT NULL,
  `recommend` varchar(10) DEFAULT NULL,
  `name` varchar(50) NOT NULL,
  `pk` varchar(5) DEFAULT NULL,
  `type` varchar(10) DEFAULT NULL,
  `width` varchar(20) DEFAULT NULL,
  `not_null` varchar(5) DEFAULT NULL,
  `is_active` tinyint(1) NOT NULL DEFAULT 1,
  PRIMARY KEY (`table_name`, `no`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;

START TRANSACTION;

;

COMMIT;
